        project: Option<String>,
        #[arg(long, help = "New task name (use empty string \"\" to remove task)")]
        task: Option<String>,
        #[arg(
            short,
            long,
            help = "Tag name (repeatable, use empty string \"\" to clear tags), e.g. -t tag1 -t tag2"
        )]
        tags: Option<Vec<String>>,
        #[arg(
