use crate::api::client::ApiClient;
use crate::models::{ResultWithDefaultError, TimeEntry};
use crate::utilities;
use std::collections::HashMap;

const ROUNDING_SECONDS: i64 = 15 * 60;
const MINIMUM_SECONDS: i64 = 30 * 60;

#[derive(Debug, Eq, PartialEq)]
struct ProjectTotal {
    name: String,
    seconds: i64,
}

fn invoice_seconds(duration: i64) -> i64 {
    let rounded = ((duration + ROUNDING_SECONDS - 1) / ROUNDING_SECONDS) * ROUNDING_SECONDS;
    rounded.max(MINIMUM_SECONDS)
}

fn project_totals(entries: &[TimeEntry]) -> Vec<ProjectTotal> {
    let mut totals: HashMap<Option<i64>, ProjectTotal> = HashMap::new();

    for entry in entries {
        // A running entry has no stop and is represented by a negative duration.
        if !entry.billable || entry.stop.is_none() || entry.duration < 0 {
            continue;
        }

        let key = entry.project.as_ref().map(|project| project.id);
        let name = entry
            .project
            .as_ref()
            .map(|project| project.name.clone())
            .unwrap_or_else(|| "No Project".to_string());
        let total = totals
            .entry(key)
            .or_insert_with(|| ProjectTotal { name, seconds: 0 });
        total.seconds += invoice_seconds(entry.duration);
    }

    let mut totals: Vec<_> = totals.into_values().collect();
    totals.sort_by(|left, right| {
        right
            .seconds
            .cmp(&left.seconds)
            .then_with(|| left.name.cmp(&right.name))
    });
    totals
}

pub struct InvoiceCommand;

impl InvoiceCommand {
    pub async fn execute(
        api_client: impl ApiClient,
        since: Option<String>,
        until: Option<String>,
    ) -> ResultWithDefaultError<()> {
        let (since, until) = utilities::normalize_time_entry_list_filters(since, until)?;
        let entries = api_client.get_time_entries_filtered(since, until).await?;
        let totals = project_totals(&entries);

        if totals.is_empty() {
            println!("(no data)");
            return Ok(());
        }

        let grand_total: i64 = totals.iter().map(|total| total.seconds).sum();
        for total in totals {
            println!("{}s  {}", total.seconds, total.name);
        }
        println!("{}s  Total", grand_total);
        Ok(())
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::models::Project;
    use chrono::{Duration, TimeZone, Utc};

    fn entry(id: i64, duration: i64, billable: bool, project: Option<(&str, i64)>) -> TimeEntry {
        let start = Utc.timestamp_opt(id, 0).single().unwrap();
        TimeEntry {
            id,
            description: String::new(),
            start,
            stop: Some(start + Duration::seconds(duration.max(0))),
            duration,
            billable,
            workspace_id: 1,
            tags: Vec::new(),
            project: project.map(|(name, id)| Project {
                id,
                name: name.to_string(),
                workspace_id: 1,
                client: None,
                is_private: false,
                active: true,
                at: start,
                created_at: start,
                color: String::new(),
                billable: None,
            }),
            task: None,
            created_with: None,
        }
    }

    #[test]
    fn rounds_each_entry_then_applies_minimum() {
        assert_eq!(invoice_seconds(1), 1800);
        assert_eq!(invoice_seconds(1800), 1800);
        assert_eq!(invoice_seconds(1801), 2700);
        assert_eq!(invoice_seconds(3600), 3600);
    }

    #[test]
    fn filters_running_and_non_billable_entries_and_sorts_totals() {
        let mut running = entry(1, -1, true, Some(("Alpha", 1)));
        running.stop = None;
        let entries = vec![
            entry(2, 1801, true, Some(("Beta", 2))),
            entry(3, 1, true, Some(("Alpha", 1))),
            entry(4, 3600, true, None),
            entry(5, 3600, false, Some(("Beta", 2))),
            running,
        ];

        assert_eq!(
            project_totals(&entries),
            vec![
                ProjectTotal {
                    name: "No Project".to_string(),
                    seconds: 3600,
                },
                ProjectTotal {
                    name: "Beta".to_string(),
                    seconds: 2700,
                },
                ProjectTotal {
                    name: "Alpha".to_string(),
                    seconds: 1800,
                },
            ]
        );
    }

    #[test]
    fn ties_are_sorted_alphabetically() {
        let entries = vec![
            entry(1, 1800, true, Some(("Zulu", 1))),
            entry(2, 1800, true, Some(("Alpha", 2))),
        ];
        let totals = project_totals(&entries);
        assert_eq!(totals[0].name, "Alpha");
        assert_eq!(totals[1].name, "Zulu");
    }
}
